	// handle nested join like "Manager.Company"
	nestedJoinNames := strings.Split(join.Name, ".")
	if len(nestedJoinNames) > 1 {
		isNestedJoin := true
		guessNestedRelations := make([]*schema.Relationship, 0, len(nestedJoinNames))
		currentRelations := db.Statement.Schema.Relationships.Relations
		for _, relname := range nestedJoinNames {
			// incomplete match, only treated as raw sql
			if relation, ok = currentRelations[relname]; ok {
				guessNestedRelations = append(guessNestedRelations, relation)
				currentRelations = relation.FieldSchema.Relationships.Relations
			} else {
				isNestedJoin = false
				break
			}
		}

		if isNestedJoin {
			isRelations = true
			relations = guessNestedRelations
		}
	}
}

for k, v := range header {
	// Forward OpenTelemetry trace propagation headers
	// These must be lowercase per gRPC metadata conventions
	if lowerKey := strings.ToLower(k); traceHeaders[lowerKey] {
		for _, vv := range v {
			headers = append(headers, lowerKey+":"+vv)
		}
		continue
	}

	// Forward custom metadata headers with Grpc-Metadata- prefix
	if !strings.HasPrefix(k, metadataHeaderPrefix) {
		continue
	}

	// gRPC metadata keys are case-insensitive and stored as lowercase,
	// so we lowercase the key to match gRPC conventions
	trimmedKey := strings.TrimPrefix(k, metadataHeaderPrefix)
	key := strings.ToLower(fmt.Sprintf("%s%s", metadataPrefix, trimmedKey))
	for _, vv := range v {
		headers = append(headers, key+":"+vv)
	}
}

if savePointer, ok := db.Dialector.(SavePointerDialectorInterface); ok {
	// close prepared statement, because SavePoint not support prepared statement.
	// e.g. mysql8.0 doc: https://dev.mysql.com/doc/refman/8.0/en/sql-prepared-statements.html
	var (
		preparedStmtTx   *PreparedStmtTX
		isPreparedStmtTx bool
	)
	// close prepared statement, because SavePoint not support prepared statement.
	if preparedStmtTx, isPreparedStmtTx = db.Statement.ConnPool.(*PreparedStmtTX); isPreparedStmtTx {
		db.Statement.ConnPool = preparedStmtTx.Tx
	}
	db.AddError(savePointer.SavePoint(db, name))
	// restore prepared statement
	if isPreparedStmtTx {
		db.Statement.ConnPool = preparedStmtTx
	}
} else {
	db.AddError(ErrUnsupportedDriver)
}

